// BuildQuest Leaderboard — reads site/data.json (regenerated by xlsx_to_json.py)

const PALETTE = ['#e2683d', '#f0a93a', '#7fbf6a', '#5fa8d3', '#c97f1e', '#b46a9c', '#7ec4cf', '#d8915c'];

function colorFor(name) {
  let h = 0;
  for (let i = 0; i < name.length; i++) h = (h * 31 + name.charCodeAt(i)) >>> 0;
  return PALETTE[h % PALETTE.length];
}

function initials(name) {
  const parts = name.trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return '?';
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return (parts[0][0] + parts[1][0]).toUpperCase();
}

function spawnEmbers() {
  const host = document.getElementById('embers');
  const count = window.innerWidth < 640 ? 10 : 18;
  for (let i = 0; i < count; i++) {
    const s = document.createElement('span');
    s.style.left = Math.random() * 100 + 'vw';
    s.style.setProperty('--drift', (Math.random() * 60 - 30) + 'px');
    s.style.animationDuration = (6 + Math.random() * 6) + 's';
    s.style.animationDelay = (Math.random() * 8) + 's';
    s.style.opacity = (0.3 + Math.random() * 0.4).toFixed(2);
    host.appendChild(s);
  }
}

let DATA = null;
let activeWeek = 'overall'; // 'overall' | 1..6

function pointsForWeek(team, week) {
  return week === 'overall' ? team.total : team.weekly[week - 1];
}

function rankedTeams(week) {
  const filterTrack = document.getElementById('trackFilter').value;
  const q = document.getElementById('search').value.trim().toLowerCase();

  let list = DATA.teams.map(t => ({ ...t, pts: pointsForWeek(t, week) }));
  list.sort((a, b) => b.pts - a.pts);
  list.forEach((t, i) => { t.localRank = i + 1; });

  if (filterTrack) list = list.filter(t => t.track === filterTrack);
  if (q) list = list.filter(t => t.team_name.toLowerCase().includes(q));
  return list;
}

function weekHasData(week) {
  if (week === 'overall') return DATA.teams.some(t => t.total > 0);
  return DATA.teams.some(t => t.weekly[week - 1] > 0);
}

function renderTabs() {
  const nav = document.getElementById('weekTabs');
  nav.innerHTML = '';
  const tabs = [{ key: 'overall', label: 'Overall' }];
  for (let w = 1; w <= DATA.num_weeks; w++) tabs.push({ key: w, label: `Week ${w}` });

  tabs.forEach(tab => {
    const btn = document.createElement('button');
    btn.textContent = tab.label;
    btn.dataset.key = tab.key;
    if (tab.key !== 'overall' && weekHasData(tab.key)) {
      const dot = document.createElement('span');
      dot.className = 'dot';
      btn.appendChild(dot);
    }
    if (String(tab.key) === String(activeWeek)) btn.classList.add('active');
    btn.addEventListener('click', () => { activeWeek = tab.key; renderAll(); });
    nav.appendChild(btn);
  });
}

function renderPodium(list) {
  const wrap = document.getElementById('podiumWrap');
  const podium = document.getElementById('podium');
  podium.innerHTML = '';

  const top3 = list.slice(0, 3);
  if (top3.length === 0 || top3.every(t => t.pts === 0)) {
    wrap.hidden = true;
    return;
  }
  wrap.hidden = false;

  const medals = ['🥇', '🥈', '🥉'];
  top3.forEach((t, i) => {
    const card = document.createElement('div');
    card.className = `p-card rank-${i + 1}`;
    card.innerHTML = `
      <span class="p-medal">${medals[i]}</span>
      <div class="p-avatar" style="background:${colorFor(t.team_name)}">${initials(t.team_name)}</div>
      <div class="p-name">${escapeHtml(t.team_name)}</div>
      <div class="p-track">${escapeHtml(t.track)}</div>
      <div class="p-points">${formatPts(t.pts)} <small>pts</small></div>
    `;
    podium.appendChild(card);
  });
}

function renderTable(list) {
  const body = document.getElementById('boardBody');
  const empty = document.getElementById('emptyState');
  body.innerHTML = '';

  if (list.length === 0 || list.every(t => t.pts === 0)) {
    document.getElementById('boardTable').hidden = true;
    empty.hidden = false;
    if (activeWeek !== 'overall' && !weekHasData(activeWeek)) {
      empty.innerHTML = `<strong>No activity logged for Week ${activeWeek} yet</strong>Check back once this week wraps up.`;
    } else {
      empty.innerHTML = `<strong>No teams match that search</strong>Try a different name or clear the track filter.`;
    }
    return;
  }
  document.getElementById('boardTable').hidden = false;
  empty.hidden = true;

  list.forEach(t => {
    const tr = document.createElement('tr');
    if (t.localRank <= 3 && activeWeek === 'overall') tr.classList.add('is-top3');
    tr.innerHTML = `
      <td class="col-rank"><span class="rank-pill">${t.localRank}</span></td>
      <td class="col-team">
        <div class="team-cell">
          <div class="mini-avatar" style="background:${colorFor(t.team_name)}">${initials(t.team_name)}</div>
          <span class="team-name">${escapeHtml(t.team_name)}</span>
        </div>
      </td>
      <td class="col-track"><span class="track-pill">${escapeHtml(t.track)}</span></td>
      <td class="col-points points-cell">${formatPts(t.pts)}</td>
    `;
    body.appendChild(tr);
  });
}

function formatPts(n) {
  return (Math.round(n * 10) / 10).toString();
}

function escapeHtml(s) {
  return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}

function populateTrackFilter() {
  const sel = document.getElementById('trackFilter');
  const tracks = [...new Set(DATA.teams.map(t => t.track))].sort();
  tracks.forEach(tr => {
    const opt = document.createElement('option');
    opt.value = tr;
    opt.textContent = tr;
    sel.appendChild(opt);
  });
}

function renderAll() {
  renderTabs();
  const list = rankedTeams(activeWeek);
  renderPodium(list);
  renderTable(list);
}

async function init() {
  spawnEmbers();
  const res = await fetch('data.json', { cache: 'no-store' });
  DATA = await res.json();

  activeWeek = DATA.current_week || 'overall';
  document.getElementById('updated').textContent =
    `Updated ${DATA.last_updated} · through Week ${DATA.current_week} · ${DATA.teams.length} teams`;

  populateTrackFilter();
  renderAll();

  document.getElementById('search').addEventListener('input', renderAll);
  document.getElementById('trackFilter').addEventListener('change', renderAll);
}

init();
